const body = $input.first().json.body;

const required = ['campaign_type','primary_text','headline','description','cta_button','image_url','audience_id','ad_account_id','daily_budget_cents','platform'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

const validPlatforms = ['facebook','instagram','both'];
if (!validPlatforms.includes(body.platform)) {
  throw new Error('platform must be facebook, instagram, or both');
}

if (body.daily_budget_cents < 100) {
  throw new Error('daily_budget_cents must be at least 100 (= $1.00)');
}

return [{ json: body }];

const adId = $('Create Ad').item.json.id;
const adSetId = $('Create Ad Set').item.json.id;
const campaignId = $('Create Campaign').item.json.id;
const payload = $('Validate Payload').item.json;

return [{
  json: {
    action: 'approve_meta_ad',
    ad_id: adId,
    ad_set_id: adSetId,
    campaign_id: campaignId,
    campaign_type: payload.campaign_type,
    platform: payload.platform,
    headline: payload.headline,
    primary_text: payload.primary_text,
    daily_budget_dollars: (payload.daily_budget_cents / 100).toFixed(2),
    created_at: new Date().toISOString(),
    message: `Ad created in PAUSED state. Review in Meta Ads Manager and approve to activate. Campaign: ${campaignId} | Ad: ${adId}`
  }
}];

const adId = $('Build Approval Payload').item.json.ad_id;
const campaignId = $('Build Approval Payload').item.json.campaign_id;
const headline = $('Build Approval Payload').item.json.headline;
const budget = $('Build Approval Payload').item.json.daily_budget_dollars;

const logEntry = `${new Date().toISOString()},${campaignId},${adId},"${headline}",${budget},ACTIVE\n`;

return [{ json: { log_entry: logEntry, ad_id: adId, campaign_id: campaignId } }];
